let x = 0, y = 0;
let xSpeed = 1, ySpeed = 1;

function setup() {
  createCanvas(400, 400);
}

function draw() {
  background(220);
  circle(x, y, 20);
  x += xSpeed;
  y += ySpeed;
  if (x > width || x < 0) { xSpeed = -xSpeed; }
  if (y > height || y < 0) { ySpeed = -ySpeed; }
}

class Disk {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.d = random(10, 40);
    this.xSpeed = random(-2, 2);
    this.ySpeed = random(-2, 2);
  }

  display() {
    push();
    translate(this.x, this.y);
    circle(0, 0, this.d);
    pop();
  }
}

// Inside a class method
this.fill = drawingContext.createRadialGradient(-5, -5, 0, this.d/2);
